  1→import { isTauri } from '../platform';
  2→import {
  3→  isStringArray,
  4→  storageGet,
  5→  storageRemove,
  6→  storageSet,
  7→} from './storage';
  8→
  9→const DB_PATH = 'sqlite:raycast_clone.db';
 10→
 11→export interface ClipboardEntryRow {
 12→  id: string;
 13→  content: string;
 14→  content_type: string;
 15→  source_app: string;
 16→  copied_at: string;
 17→  pinned: number;
 18→}
 19→
 20→export interface SnippetRow {
 21→  id: string;
 22→  name: string;
 23→  keyword: string;
 24→  content: string;
 25→  category: string;
 26→  tags: string;
 27→  created_at: string;
 28→}
 29→
 30→export interface QuicklinkRow {
 31→  id: string;
 32→  name: string;
 33→  link: string;
 34→  type: string;
 35→  application: string | null;
 36→  tags: string;
 37→  created_at: string;
 38→}
 39→
 40→export interface NoteRow {
 41→  id: string;
 42→  title: string;
 43→  content: string;
 44→  created_at: string;
 45→  updated_at: string;
 46→}
 47→
 48→export interface RecentCommandRow {
 49→  id: number;
 50→  command_id: string;
 51→  used_at: string;
 52→}
 53→
 54→export interface SettingRow {
 55→  key: string;
 56→  value: string;
 57→}
 58→
 59→type DatabaseInstance = {
 60→  execute(
 61→    query: string,
 62→    bindValues?: unknown[],
 63→  ): Promise<{ rowsAffected: number }>;
 64→  select<T>(query: string, bindValues?: unknown[]): Promise<T>;
 65→};
 66→
 67→let dbInstance: DatabaseInstance | undefined;
 68→let dbPromise: Promise<DatabaseInstance> | undefined;
 69→
 70→async function loadDb(): Promise<DatabaseInstance> {
 71→  const Database = (await import('@tauri-apps/plugin-sql')).default;
 72→  return Database.load(DB_PATH);
 73→}
 74→
 75→function getDb(): Promise<DatabaseInstance> {
 76→  if (dbInstance) return Promise.resolve(dbInstance);
 77→  if (dbPromise) return dbPromise;
 78→
 79→  dbPromise = loadDb()
 80→    .then(db => {
 81→      dbInstance = db;
 82→      return db;
 83→    })
 84→    .catch(err => {
 85→      dbPromise = undefined;
 86→      throw err;
 87→    });
 88→
 89→  return dbPromise;
 90→}
 91→
 92→const CLIPBOARD_COLUMNS = new Set<string>([
 93→  'content',
 94→  'content_type',
 95→  'source_app',
 96→  'copied_at',
 97→  'pinned',
 98→]);
 99→
100→const SNIPPET_COLUMNS = new Set<string>([
101→  'name',
102→  'keyword',
103→  'content',
104→  'category',
105→  'tags',
106→  'created_at',
107→]);
108→
109→const QUICKLINK_COLUMNS = new Set<string>([
110→  'name',
111→  'link',
112→  'type',
113→  'application',
114→  'tags',
115→  'created_at',
116→]);
117→
118→const NOTE_COLUMNS = new Set<string>([
119→  'title',
120→  'content',
121→  'created_at',
122→]);
123→
124→function buildUpdateQuery(
125→  table: string,
126→  updates: Record<string, unknown>,
127→  allowedColumns: Set<string>,
128→  id: string
129→): {
130→  sql: string;
131→  values: unknown[];
132→} | null {
133→  const fields: string[] = [];
134→  const values: unknown[] = [];
135→  let idx = 1;
136→
137→  for (const [key, value] of Object.entries(updates)) {
138→    if (!allowedColumns.has(key)) continue;
139→    fields.push(`${key} = $${idx}`);
140→    values.push(value);
141→    idx++;
142→  }
143→
144→  if (fields.length === 0) return null;
145→  values.push(id);
146→  return {
147→    sql: `UPDATE ${table} SET ${fields.join(', ')} WHERE id = $${idx}`,
148→    values,
149→  };
150→}
151→
152→function escapeFts5Query(query: string): string {
153→  return query
154→    .split(/\s+/)
155→    .filter(Boolean)
156→    .map(token => `"${token.replace(/"/g, '""')}"`)
157→    .join(' ');
158→}
159→
160→function isClipboardRowArray(v: unknown): v is ClipboardEntryRow[] {
161→  if (!Array.isArray(v)) return false;
162→  return v.every(
163→    r =>
164→      typeof r === 'object' &&
165→      r !== null &&
166→      'id' in r &&
167→      typeof r.id === 'string' &&
168→      'content' in r &&
169→      typeof r.content === 'string' &&
170→      'copied_at' in r &&
171→      typeof r.copied_at === 'string',
172→  );
173→}
174→
175→function isSnippetRowArray(v: unknown): v is SnippetRow[] {
176→  if (!Array.isArray(v)) return false;
177→  return v.every(
178→    r =>
179→      typeof r === 'object' &&
180→      r !== null &&
181→      'id' in r &&
182→      typeof r.id === 'string' &&
183→      'name' in r &&
184→      typeof r.name === 'string',
185→  );
186→}
187→
188→function isQuicklinkRowArray(v: unknown): v is QuicklinkRow[] {
189→  if (!Array.isArray(v)) return false;
190→  return v.every(
191→    r =>
192→      typeof r === 'object' &&
193→      r !== null &&
194→      'id' in r &&
195→      typeof r.id === 'string' &&
196→      'name' in r &&
197→      typeof r.name === 'string' &&
198→      'link' in r &&
199→      typeof r.link === 'string',
200→  );
201→}
202→
203→function isNoteRowArray(v: unknown): v is NoteRow[] {
204→  if (!Array.isArray(v)) return false;
205→  return v.every(
206→    r =>
207→      typeof r === 'object' &&
208→      r !== null &&
209→      'id' in r &&
210→      typeof r.id === 'string' &&
211→      'title' in r &&
