213→  );
214→}
215→
216→function isSettingRowArray(v: unknown): v is SettingRow[] {
217→  if (!Array.isArray(v)) return false;
218→  return v.every(
219→    r =>
220→      typeof r === 'object' &&
221→      r !== null &&
222→      'key' in r &&
