         WHERE quicklinks_fts MATCH $1
         ORDER BY q.created_at DESC
         LIMIT $2`,
        [
          escaped,
          limit,
        ],
      );
    }
    const all = await this.getAll();
    const q = query.toLowerCase();
    return all
      .filter(
        r =>
          r.name.toLowerCase().includes(q) || r.link.toLowerCase().includes(q),
